<?php
require_once __DIR__.'/includes/auth.php';require_admin();$pdo=db();$id=(int)get_query_param('id','0');$s=$pdo->prepare('SELECT c.*,u.username FROM email_campaigns c LEFT JOIN users u ON u.id=c.created_by WHERE c.id=:id');$s->execute([':id'=>$id]);$c=$s->fetch();if(!$c){http_response_code(404);exit('キャンペーンが見つかりません。');}$r=$pdo->prepare('SELECT status,COUNT(*) count,MAX(last_error) last_error FROM email_campaign_recipients WHERE campaign_id=:id GROUP BY status');$r->execute([':id'=>$id]);$results=$r->fetchAll();$pageTitle='キャンペーン詳細 | '.APP_NAME;include __DIR__.'/includes/header.php';?>
<section class="card"><h2>キャンペーン #<?=e($id)?></h2><dl class="detail-grid"><dt>件名</dt><dd><?=e($c['subject'])?></dd><dt>本文</dt><dd><pre class="mail-preview"><?=e($c['body_text'])?></pre></dd><dt>状態</dt><dd><?=e($c['status'])?></dd><dt>送信元</dt><dd><?=e($c['from_name'])?> &lt;<?=e($c['from_address'])?>&gt;</dd><dt>返信先</dt><dd><?=e($c['reply_to'])?></dd><dt>対象条件</dt><dd>配信同意済みの有効ユーザー</dd></dl></section><section class="card"><h3>送信結果</h3><ul><?php foreach($results as $v):?><li><?=e($v['status'])?>: <?=e($v['count'])?>件<?php if($v['status']==='failed'):?>（理由: <?=e($v['last_error']??'送信エラー')?>）<?php endif?></li><?php endforeach?></ul><?php if(in_array($c['status'],['queued','sending'],true)):?><a class="btn danger" href="admin_email_cancel.php?id=<?=e($id)?>">配信キャンセル確認</a><?php endif?> <a class="btn" href="admin_email_campaigns.php">履歴へ戻る</a></section><?php include __DIR__.'/includes/footer.php';
